export function getQuestionsByGradeAndSubject(
  grade: number,
  subject: 'chinese' | 'math' | 'english' | 'science'
): Question[] {
  return allGradedQuestions.filter(q => q.grade === grade && q.category === subject)
}

export function getQuestionsByDifficulty(difficulty: number): Question[] {
  return allGradedQuestions.filter(q => q.difficulty === difficulty)
}

